    fun addControlPreferencesToCategories(
        answerButtonsCategory: PreferenceCategory,
        flagsCategory: PreferenceCategory,
        whiteboardCategory: PreferenceCategory,
        cardNoteCategory: PreferenceCategory,
        navigationCategory: PreferenceCategory,
        miscCategory: PreferenceCategory
    ) {
        for (command in ViewerCommand.values()) {
            val preference = ControlPreference(answerButtonsCategory.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }

            val targetCategory = when (command) {
                // Answer buttons
                ViewerCommand.SHOW_ANSWER,
                ViewerCommand.FLIP_OR_ANSWER_EASE1,
                ViewerCommand.FLIP_OR_ANSWER_EASE2,
                ViewerCommand.FLIP_OR_ANSWER_EASE3,
                ViewerCommand.FLIP_OR_ANSWER_EASE4 -> answerButtonsCategory

                // Flags
                ViewerCommand.TOGGLE_FLAG_RED,
                ViewerCommand.TOGGLE_FLAG_ORANGE,
                ViewerCommand.TOGGLE_FLAG_GREEN,
                ViewerCommand.TOGGLE_FLAG_BLUE,
                ViewerCommand.TOGGLE_FLAG_PINK,
                ViewerCommand.TOGGLE_FLAG_TURQUOISE,
                ViewerCommand.TOGGLE_FLAG_PURPLE,
                ViewerCommand.UNSET_FLAG -> flagsCategory

                // Whiteboard
                ViewerCommand.TOGGLE_WHITEBOARD,
                ViewerCommand.CLEAR_WHITEBOARD,
                ViewerCommand.CHANGE_WHITEBOARD_PEN_COLOR -> whiteboardCategory

                // Current card/note operations
                ViewerCommand.SUSPEND_CARD,
                ViewerCommand.SUSPEND_NOTE,
                ViewerCommand.DELETE,
                ViewerCommand.BURY_CARD,
                ViewerCommand.BURY_NOTE,
                ViewerCommand.MARK,
                ViewerCommand.EDIT,
                ViewerCommand.TAG,
                ViewerCommand.CARD_INFO,
                ViewerCommand.RESCHEDULE_NOTE -> cardNoteCategory

                // Navigation
                ViewerCommand.PAGE_UP,
                ViewerCommand.PAGE_DOWN,
                ViewerCommand.EXIT,
                ViewerCommand.ABORT_AND_SYNC -> navigationCategory

                // Miscellaneous - everything else
                else -> miscCategory
            }

            targetCategory.addPreference(preference)
        }
    }

    /** Attaches all possible [ControlPreference] elements to a given [PreferenceCategory] */
    @Deprecated("Use addControlPreferencesToCategories instead")
    fun addAllControlPreferencesToCategory(category: PreferenceCategory) {
        for (command in ViewerCommand.values()) {
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }"}

